mapper.select:
SELECT 
FROM cm_emission_factor
WHERE deleted = 0

    AND factor_name LIKE CONCAT('%', #{factorName}, '%')


    AND energy_type = #{energyType}


    AND effective_year = #{effectiveYear}


    AND status = #{status}

ORDER BY effective_year DESC, energy_type, id

mapper.update:
UPDATE cm_emission_factor
SET deleted = 1, update_by = #{updateBy}, update_time = NOW()
WHERE id = #{id}
